KMP算法模板及原理
KMP 模式串匹配算法
暴力解法： s[n],p[m]for(int i = 1; i &lt;= n; i++) &#123; bool flag; for (int j = 1; j &lt;= m; j++) &#123; if (s[i] != p[j]) &#123; flag = false; break; &#125; &#125;&#125;
问题：在BF算法中，用模式串去和目标串的某个子串比较时，如果不全部匹配，就要回溯到起始位置，然后后移。 KMP算法的思想是，设法利用已知信息，跳过前面已经比较过的位置，把模式串后移，使最长前缀的一块后移到模式串最长后缀的位置，再次比较不匹配的字符，再不匹配再回退，直到回退到模式串的第一个字符，还不匹配就后移目标串，这样就提高了效率。 由此可知，KMP算法其实有两大要点： (1) 计算跳转位置信息，也就是计算next数组值。 (2) 后移到指定位置，重新开始匹配。 算法性能 假设模式串的长度是m，目标串的长度是n。 在KMP算法中求next数组的时间复杂度为O(m)，在后面的匹配中因目标串T的下标不用回溯，所以比较次数可记为n。 由此，得出KMP算法的总的时间复杂度为O(n+m)。 javacode int n, m;String pstr, sstr;int[] ne = new int[N];Scanner scanner = new Scanner(System.in);pstr = scanner.next();sstr = scanner.next();m = pstr.length();n = sstr.length();char[] p = new char[m + 1];char[] s = new char[n + 1];System.arraycopy(pstr.toCharArray(), 0, p, 1, m);System.arraycopy(sstr.toCharArray(), 0, s, 1, n);-----求next数组模板---------for (int i = 2, j = 0; i &lt;= m; i++) &#123; while (j != 0 &amp;&amp; p[i] != p[j + 1]) &#123; j = ne[j]; &#125; if (p[i] == p[j + 1]) &#123; j++; &#125; ne[i] = j;&#125;------匹配模板--for (int i = 1, j = 0; i &lt;= n; i++) &#123; while (j != 0 &amp;&amp; s[i] != p[j + 1]) &#123; j = ne[j]; &#125; if (s[i] == p[j + 1]) &#123; j++; &#125; if (j == m) &#123; System.out.println(i - m); j = ne[j]; &#125;&#125;
cppcode #include&lt;iostream&gt;using namespace std;int main()&#123; int n, m; char p[10010], s[10010]; int next[1000]; cin &gt;&gt; m &gt;&gt; p + 1 &gt;&gt; n &gt;&gt; s + 1; // s是长文本，p是模式串，n是s的长度，m是p的长度 for (int i = 2, j = 0; i &lt;= m; i++) &#123; //求next数组的过程其实就是对模式串本身求kmp匹配的过程，前缀和后缀匹配 while (j &amp;&amp; p[i] != p[j + 1]) j = next[j]; if (p[i] == p[j + 1]) j++; next[i] = j; &#125; for (int i = 1, j = 0; i &lt;= n; i++) &#123; while (j &amp;&amp; s[i] != p[j + 1]) j = next[j]; if (s[i] == p[j + 1]) j++; if (j == m) &#123; cout &lt;&lt; i - m &lt;&lt; endl; j = next[j]; &#125; &#125;&#125;
kmp匹配过程中是模式串和目标串匹配，i指向目标串中的字符，j+1指向模式串中的字符，当s[i] != p[j + 1]的时候，就会让j回退到next[j]，用p[j + 1]和s[i]再次比较，因此p[j] == p[next[j]]，除非回退到开头，所以在求next数组的时候j++ if (p[i] == p[j + 1]) j++;next[i] = j;
是为了让p[j] == p[next[j]]。 所以以上过程中，next[j]的含义是，当第&#x3D;&#x3D;j + 1&#x3D;&#x3D;位置上的字符不匹配时，j回退到哪，而匹配始终是j + 1个字符进行和目标串匹配。

记录算法学习过程中的算法模板，主要以 数组 模拟各种数据结构为主



单链表int N = 100010, idx, head;int e[N], ne[N]; // 记录节点值，和下一个节点位置void init () &#123;    head = -1;    idx = 0;&#125;// 头插法void add_Firdt(int x) &#123;    e[idx] = x;    ne[idx] = head;    head = idx++;&#125;// 删除头结点（头结点要存在）void remove(int a) &#123;    head = ne[head];&#125;

双链表int N = 100010, idx;int l[N], r[N];void init () &#123;    // 手动设置头尾节点，在01之间插入数据    l[1] = 0;    r[0] = 1;    idx = 2;&#125;// 在节点a的右边插入xvoid insert (int a, int x) &#123;    e[idx] = x;    r[idx] = r[a];    l[idx] = a;    l[r[idx]] = idx;    r[a] = idx++;&#125;// 删除节点avoid remove (int a) &#123;    r[l[a]] = r[a];    l[r[a]] = l[a];&#125;

栈int tt = 0, N = 100010; // 表示栈顶int skt[N];// 添加,数组从1号位开始使用，这样当栈顶tt==0时可以直接判空skt[++tt] = x;// 删除tt--;// 栈顶的值skt[tt];// 判空if (tt &gt; 0) &#123;&#125;

普通队列int q[N], hh = 0, tt = -1;// 尾插q[++tt] = x;// 从队头弹出hh++;// 队头的值q[hh];// 判空if (hh &lt;= tt) &#123;    &quot;非空&quot;&#125;

循环队列// hh 表示队头，tt表示队尾的后一个位置int q[N], hh = 0, tt = 0;// 向队尾插入一个数q[tt ++ ] = x;if (tt == N) tt = 0;// 从队头弹出一个数hh ++ ;if (hh == N) hh = 0;// 队头的值q[hh];// 判断队列是否为空if (hh != tt)&#123;&#125;

单调栈
单调栈的使用有限，经典的题目：给定一个数组，返回距离每个数，最近的，左（有）边，比他大(小)的数

思路分析：以比他大的为例
暴力算法，遍历每个数，然后从哪个数向左右两边遍历
单调栈做法：

求左右两侧：将数组中的数从左到右挨个放入栈中，保证栈内元素是单调递减的(栈底到栈顶)，当某个数加入栈失败（意思就是当前这个数比栈顶元素大，一旦入栈就破坏了单调栈的规则）那么此时的栈顶元素，右侧，最近的比他大的数就是待入栈元素，左侧最近比他大的元素就是栈顶元素前一个元素，可以理解为二次函数，对称轴就是栈顶元素，左右两侧都比他大，将结果保存在数组中，栈和数组都只保存下标,另开数组保存值和结果，同理求比他小的话，要保证栈内元素单调增。

求单侧：如果只求一侧最大或者最小值的话，不需要输入数组保存输入值，如果是左侧不需要专门用一个数组来保存结果，因为每个数放进去就知道答案了（小于栈顶就是栈顶，大于栈顶就出栈到能放入时的栈顶），如果求的是右侧，就需要一个数组保存结果了，因为你不知道你的右侧什么时候会来符合结果的解，只能放进数组中保存，等所有数据入栈完毕，结果数组也就被填充完毕！


// 求左侧大static int N = 100010;public static void main(String[] args) &#123;    int[] s = new int [N];    int tt = 0;    int n = scanner.nextInt();    for (int i = 0; i &lt; n; i++) &#123;        int x = scanner.nextInt();        while (tt &gt; 0 &amp;&amp; x &gt;= s[tt]) &#123; // 栈不为空，且栈顶元素小于当前元素            tt--;        &#125;        if (tt == 0) &#123;            System.out.print(&quot;-1 &quot;);        &#125;        if (x &lt; s[tt]) &#123;            System.out.println(tt + &quot; &quot;);        &#125;        s[++tt] = x;    &#125;&#125;// 求左侧小，直接将第九行while(tt &gt; 0 &amp;&amp; x &gt;= s[tt])中的&gt;= 改为&lt;=,其他完全一样while (tt &gt; 0 &amp;&amp; x &lt;= s[tt])// 求两侧大static int N;public static void main(String[] args) &#123;    N = scanner.nextInt() + 10;     int[] s = new int[N];    int[] e = new int[N];    int[] l = new int[N];    int[] r = new int[N];    int tt = 0;// 栈顶    Arrays.fill(l, -1);    Arrays.fill(r, -1);    int n = scanner.nextInt();    for (int i = 1; i &lt;= n; i++) &#123;        int x = scanner.nextInt();        e[i] = x;        while (tt &gt; 0 &amp;&amp; x &gt;= e[s[tt]]) &#123; // 栈不为空，且栈顶元素小于当前元素            r[s[tt]] = i;            tt--;        &#125;        if (tt == 0) &#123;            l[i] = -1;        &#125; else &#123;            l[i] = s[tt];        &#125;        s[++tt] = i;    &#125;    for (int i = 1; i &lt;= n; i++) &#123;        System.out.println(l[i] + &quot; &quot; + r[i]);    &#125;&#125;

单调队列
滑动窗口：返回窗口从左到右过程中，每一刻窗口中最大值或者最小值

暴力做法：每次遍历窗口中所有数据，时间复杂度O(nk)
优化：类似于单调栈，将没有用的数据从队列中弹出，求以窗口最大值为例，保持队列中下标的值是单调减的（求的就是窗口中的最大值），那么新添加的下标的值如果小于等于队尾，那么直接添加，如果大于队尾，不停出队，直到可以保证单调性添加为止。每次输出用队头元素下标和当前下标相比，判断窗口是否经过，如果经过了，收缩队头。
const int N = 100010;int main() &#123;	int n, k;    // 输入n个数，窗口大小k	cin &gt;&gt; n &gt;&gt; k;	int a[N];	for (int i = 0; i &lt; n; i++) cin &gt;&gt; a[i];	int q[N];	int hh = 0, tt = -1;	for (int i = 0; i &lt; n; i++) &#123;        // 队不为空，且队头下标小于窗口左侧，即窗口已经离开，收缩队列		if (hh &lt;= tt &amp;&amp; i - k + 1 &gt; q[hh]) hh++;         // 收缩队尾		while (hh &lt;= tt &amp;&amp; a[q[tt]] &gt;= a[i]) tt--;		q[++tt] = i;		if (i &gt;= k - 1) cout &lt;&lt; a[q[hh]]; 	&#125;        hh = 0, tt = -1;	for (int i = 0; i &lt; n; i++) &#123;        // 队不为空，且队头下标小于窗口左侧，即窗口已经离开，收缩队列		if (hh &lt;= tt &amp;&amp; i - k + 1 &gt; q[hh]) hh++;         // 收缩队尾		while (hh &lt;= tt &amp;&amp; a[q[tt]] &lt;= a[i]) tt--;// 这里改成&lt;=就是求窗口最大值		q[++tt] = i;		if (i &gt;= k - 1) cout &lt;&lt; a[q[hh]]; 	&#125;	return 0;&#125;

记录一次查询异常
使用mysql进行字符串相关函数的学习时发现，当时用函数substring时，可以正常运行，但是使用SQLyog的SQL格式器格式化SQL语句后报错，后来经过排查发现，格式化后自动在函数名后面加了空格，导致错误 -- 格式化前：SELECT SUBSTRING(ename, 1, 2)FROM emp; -- 格式化后：SELECT SUBSTRING (ename, 1, 2)FROM emp;
后来发现，大部分的函数名和参数列表之间添加空格都不会影响SQL语句的执行，但是为了一劳永逸，查找了解决办法在mysql的安装路径的个人配置文件my.ini文件中添加下面语句，切记不要在末尾添加分号！ sql_mode=&#x27;IGNORE_SPACE&#x27;
添加完毕后使用管理员身份运行cmd,输入以下指令重启mysql服务器 net stop mysqlnet start mysql
这样即使函数之间有空格也不会报错啦！

前言：前些日子在写一道算法题的时候遇到一件怪事，关于输入输出格式化的问题，当时稀里糊涂的就Ac了，现在来研究一下。
问题回顾：输入一个整数N，接下来输入大于N行的字符串 要求：前N行数据直接输出，剩余行数据按照空格分割输出。 input3aa aaabbb bbcccc caa bb cc dd
printaa aaabbb bbcccc caabbccdd
代码回顾：import java.util.*;public class Main &#123; public static void main(String[] args) &#123; Scanner s = new Scanner(System.in); int N = s.nextInt(); while (s.hasNextLine())&#123; String cin = s.nextLine(); N--; if (N &gt;= 0) &#123; System.out.println(cin); &#125; else &#123; String[] arr = cin.split(&quot; &quot;); for (String str : arr) &#123; System.out.println(str); &#125; &#125; &#125; &#125;&#125;
我的第一版代码是这样的，可是wa了，运行结果和我想的有点出入，我调试了一下，发现少了一行数据，输出结果是这样的： aa aaabbb bbcccc caabbccdd
原本应该输出3行原格式字符串的，这是为什么呢？ 后来我才while循环外面加了一个s.nextLine()结果就Ac了。 我看了一下源码，并结合调试结果找到了答案。 首先nextInt()方法是没法读入回车的，这就导致在输入3之后的那个回车留在了while循环里读了，所以这个回车就占了一次输入次数，所以结果少了一次。 源码解析字段//缓冲区是特定原始类型元素的线性、有限序列。除了内容之外，缓冲区的基本属性还有capacity、limit和position：capacity //缓冲区的容量是它包含的元素数。缓冲区的容量永远不会是负数，也永远不会改变。limit //缓冲区的限制是不应读取或写入的第一个元素的索引。缓冲区的限制永远不会是负数，也永远不会大于其容量。position //缓冲区的位置是要读取或写入的下一个元素的索引。缓冲区的位置永远不会是负数，也永远不会大于其限制
next方法public String next() &#123; ensureOpen(); //清理规则缓存和类型缓存 hasNextPattern = null;typeCache = null; clearCaches(); while (true) &#123; String token = getCompleteTokenInBuffer(null); if (token != null) &#123; matchValid = true; skipped = false; return token; &#125; if (needInput) readInput(); else throwFor(); &#125;&#125;
getCompleteTokenInBuffer方法private String getCompleteTokenInBuffer(Pattern pattern) &#123; matchValid = false; // 首先跳过delim //设置matcher的parentPattern为delimPattern matcher.usePattern(delimPattern); if (!skipped) &#123; // 仅强制执行前导delim的一次跳过 // 设定matcher匹配区域，默认from=0，end=0 matcher.region(position, buf.limit()); if (matcher.lookingAt()) &#123; //如果更多的输入可以扩展分隔符，那么我们必须等待 //获得更多输入 if (matcher.hitEnd() &amp;&amp; !sourceClosed) &#123; needInput = true; return null; &#125; // delims 是完整的，matcher 应该跳过它们 skipped = true; position = matcher.end(); &#125; &#125; // If we are sitting at the end, no more tokens in buffer if (position == buf.limit()) &#123; if (sourceClosed) return null; needInput = true; return null; &#125; // Must look for next delims. Simply attempting to match the // pattern at this point may find a match but it might not be // the first longest match because of missing input, or it might // match a partial token instead of the whole thing. // Then look for next delims matcher.region(position, buf.limit()); boolean foundNextDelim = matcher.find(); if (foundNextDelim &amp;&amp; (matcher.end() == position)) &#123; // Zero length delimiter match; we should find the next one // using the automatic advance past a zero length match; // Otherwise we have just found the same one we just skipped foundNextDelim = matcher.find(); &#125; if (foundNextDelim) &#123; // In the rare case that more input could cause the match // to be lost and there is more input coming we must wait // for more input. Note that hitting the end is okay as long // as the match cannot go away. It is the beginning of the // next delims we want to be sure about, we don&#x27;t care if // they potentially extend further. if (matcher.requireEnd() &amp;&amp; !sourceClosed) &#123; needInput = true; return null; &#125; int tokenEnd = matcher.start(); // There is a complete token. if (pattern == null) &#123; // Must continue with match to provide valid MatchResult pattern = FIND_ANY_PATTERN; &#125; // Attempt to match against the desired pattern matcher.usePattern(pattern); matcher.region(position, tokenEnd); if (matcher.matches()) &#123; String s = matcher.group(); position = matcher.end(); return s; &#125; else &#123; // Complete token but it does not match return null; &#125; &#125; // If we can&#x27;t find the next delims but no more input is coming, // then we can treat the remainder as a whole token if (sourceClosed) &#123; if (pattern == null) &#123; // Must continue with match to provide valid MatchResult pattern = FIND_ANY_PATTERN; &#125; // Last token; Match the pattern here or throw matcher.usePattern(pattern); matcher.region(position, buf.limit()); if (matcher.matches()) &#123; String s = matcher.group(); position = matcher.end(); return s; &#125; // Last piece does not match return null; &#125; // There is a partial token in the buffer; must read more // to complete it needInput = true; return null;&#125;
